1) 파일: supabase/migrations/20260504000002_create_categories.sql
2) 주요 SQL:
   CREATE TABLE IF NOT EXISTS public.categories (
     id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
     slug TEXT NOT NULL UNIQUE,
     name TEXT NOT NULL,
     type TEXT NOT NULL CHECK (type IN ('topic','campus')),
     sort_order INTEGER NOT NULL DEFAULT 0,
     is_active BOOLEAN NOT NULL DEFAULT true,
     created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
     updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
   );
   CREATE INDEX IF NOT EXISTS idx_categories_type_sort ON public.categories (type, sort_order);
   ALTER TABLE public.categories ENABLE ROW LEVEL SECURITY;
3) RLS 4정책 (DROP IF EXISTS + CREATE 패턴으로 idempotent):
   DROP POLICY IF EXISTS categories_select_all ON public.categories;
   CREATE POLICY categories_select_all ON public.categories FOR SELECT USING (true);
   DROP POLICY IF EXISTS categories_insert_admin ON public.categories;
   CREATE POLICY categories_insert_admin ON public.categories FOR INSERT WITH CHECK (public.is_admin());
   DROP POLICY IF EXISTS categories_update_admin ON public.categories;
   CREATE POLICY categories_update_admin ON public.categories FOR UPDATE USING (public.is_admin()) WITH CHECK (public.is_admin());
   DROP POLICY IF EXISTS categories_delete_admin ON public.categories;
   CREATE POLICY categories_delete_admin ON public.categories FOR DELETE USING (public.is_admin());
4) 트리거: DROP TRIGGER IF EXISTS categories_set_updated_at ON public.categories; CREATE TRIGGER categories_set_updated_at BEFORE UPDATE ON public.categories FOR EACH ROW EXECUTE FUNCTION public.set_updated_at();
